#!/bin/bash
if [[ "$1" == "--execute" ]]; then
    read sessionKey
    CELLNAME=$(echo $sessionKey | jq .configuration.cellname | sed 's/"//g')
    CLASS=$(echo $sessionKey | jq .configuration.class | sed 's/"//g')
    MESSAGE=$(echo $sessionKey | jq .configuration.message | sed 's/"//g')
    CYCLE_GUID=$(echo $sessionKey | jq .configuration.cycle_guid | sed 's/"//g')
    EVENT_REPORTED_TIME=$(echo $sessionKey | jq .configuration.event_reported_time | sed 's/"//g')
    HOST_NAME=$(echo $sessionKey | jq .configuration.host_name | sed 's/"//g')
    REPEAT_COUNT=$(echo $sessionKey | jq .configuration.repeat_count | sed 's/"//g')
    RULE_OWNER=$(echo $sessionKey | jq .configuration.rule_owner | sed 's/"//g')
    RULESET_NAME=$(echo $sessionKey | jq .configuration.ruleset_name | sed 's/"//g')
    TARGET_NAME=$(echo $sessionKey | jq .configuration.target_name | sed 's/"//g')
    TARGET_TYPE=$(echo $sessionKey | jq .configuration.target_type | sed 's/"//g')
    ISSUE_TYPE=$(echo $sessionKey | jq .configuration.issue_type | sed 's/"//g')
    MESSAGE_URL=$(echo $sessionKey | jq .configuration.message_url | sed 's/"//g')
    SEVERITY=$(echo $sessionKey | jq .configuration.severity | sed 's/"//g')
    SEVERITY_CODE=$(echo $sessionKey | jq .configuration.severity_code | sed 's/"//g')
    RULE_NAME=$(echo $sessionKey | jq .configuration.rule_name | sed 's/"//g')
    CATEGORIES_COUNT=$(echo $sessionKey | jq .configuration.categories_count | sed 's/"//g')
    CATEGORY_1=$(echo $sessionKey | jq .configuration.category_1 | sed 's/"//g')
    CATEGORY_CODES_COUNT=$(echo $sessionKey | jq .configuration.category_codes_count | sed 's/"//g')
    SEQUENCE_ID=$(echo $sessionKey | jq .configuration.sequence_id | sed 's/"//g')
    NUM_KEYS=$(echo $sessionKey | jq .configuration.num_keys | sed 's/"//g')
    KEY_VALUE_NAME=$(echo $sessionKey | jq .configuration.key_value_name | sed 's/"//g')
    LAST_UPDATE_TIME=$(echo $sessionKey | jq .configuration.last_update_time | sed 's/"//g')
    NOTIF_TYPE=$(echo $sessionKey | jq .configuration.notif_type | sed 's/"//g')
    METRIC_COLUMN=$(echo $sessionKey | jq .configuration.metric_column | sed 's/"//g')
    VALUE=$(echo $sessionKey | jq .configuration.value | sed 's/"//g')
    SEVERITY_GUID=$(echo $sessionKey | jq .configuration.severity_guid | sed 's/"//g')
    EVENT_TYPE=$(echo $sessionKey | jq .configuration.event_type | sed 's/"//g')
    EVENT_NAME=$(echo $sessionKey | jq .configuration.event_name | sed 's/"//g')
    EVENT_TYPE_ATTRS=$(echo $sessionKey | jq .configuration.event_type_attrs | sed 's/"//g')
    SOURCE_OBJ_NAME=$(echo $sessionKey | jq .configuration.source_obj_name | sed 's/"//g')
    SOURCE_OBJ_TYPE=$(echo $sessionKey | jq .configuration.source_obj_type | sed 's/"//g')
    SOURCE_OBJ_OWNER=$(echo $sessionKey | jq .configuration.source_obj_owner | sed 's/"//g')
    TARGET_URL=$(echo $sessionKey | jq .configuration.target_url | sed 's/"//g')
    TARGET_OWNER=$(echo $sessionKey | jq .configuration.target_owner | sed 's/"//g')
    TARGET_VERSION=$(echo $sessionKey | jq .configuration.target_version | sed 's/"//g')
    ASSOC_INCIDENT_ESCALATION_LEVEL=$(echo $sessionKey | jq .configuration.assoc_incident_escalation_level | sed 's/"//g')
    ASSOC_INCIDENT_ID=$(echo $sessionKey | jq .configuration.assoc_incident_id | sed 's/"//g')
    ASSOC_INCIDENT_OWNER=$(echo $sessionKey | jq .configuration.assoc_incident_owner | sed 's/"//g')
    ASSOC_INCIDENT_ACKNOWLEDGED_BY_OWNER=$(echo $sessionKey | jq .configuration.assoc_incident_acknowledged_by_owner | sed 's/"//g')
    ASSOC_INCIDENT_ACKNOWLEDGED_DETAILS=$(echo $sessionKey | jq .configuration.assoc_incident_acknowledged_details | sed 's/"//g')
    ASSOC_INCIDENT_PRIORITY=$(echo $sessionKey | jq .configuration.assoc_incident_priority | sed 's/"//g')
    ASSOC_INCIDENT_STATUS=$(echo $sessionKey | jq .configuration.assoc_incident_status | sed 's/"//g')
fi

./msend -n ${CELLNAME} -a ${CLASS} -b "msg='$MESSAGE';oem_cycle_guid='$CYCLE_GUID';oem_event_reported_time='$EVENT_REPORTED_TIME';oem_host_name='$HOST_NAME';oem_message='$MESSAGE';oem_repeat_count='$REPEAT_COUNT';oem_rule_owner='$RULE_OWNER';oem_ruleset_name='$RULESET_NAME';oem_target_name='$TARGET_NAME';oem_target_type='$TARGET_TYPE';oem_issue_type='$ISSUE_TYPE';oem_message_url='$MESSAGE_URL';oem_severity='$SEVERITY';oem_severity_code='$SEVERITY_CODE';oem_rule_name='$RULE_NAME';oem_categories_count='$CATEGORIES_COUNT';oem_category_1='$CATEGORY_1';oem_category_code_1='$CATEGORY_1';oem_category_codes_count='$CATEGORY_CODES_COUNT';oem_sequence_id='$SEQUENCE_ID';oem_num_keys='$NUM_KEYS';oem_key_value_name='$KEY_VALUE_NAME';oem_last_updated_time='$LAST_UPDATE_TIME';oem_notif_type='$NOTIF_TYPE';oem_metric_column='$METRIC_COLUMN';oem_value='$VALUE';oem_severity_guid='$SEVERITY_GUID';oem_event_type='$EVENT_TYPE';oem_event_name='$EVENT_NAME';oem_event_type_attrs='$EVENT_TYPE_ATTRS';oem_source_obj_name='$SOURCE_OBJ_NAME';oem_source_obj_type='$SOURCE_OBJ_TYPE';oem_source_obj_owner='$SOURCE_OBJ_OWNER';oem_target_url='$TARGET_URL';oem_target_owner='$TARGET_OWNER';oem_target_version='$TARGET_VERSION';oem_assoc_incident_escalation_level='$ASSOC_INCIDENT_ESCALATION_LEVEL';oem_assoc_incident_id='$ASSOC_INCIDENT_ID';oem_assoc_incident_owner='$ASSOC_INCIDENT_OWNER';oem_assoc_incident_acknowledged_by_owner='$ASSOC_INCIDENT_ACKNOWLEDGED_BY_OWNER';oem_assoc_incident_acknowledged_details='$ASSOC_INCIDENT_ACKNOWLEDGED_DETAILS';oem_assoc_incident_priority='$ASSOC_INCIDENT_PRIORITY';oem_assoc_incident_status='$ASSOC_INCIDENT_STATUS';" > /tmp/output.msend
